object SessionTokenGenerator {
    private const val CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789" + "-_" // base 62 alphanumeric characters (letters, digits and special)
    private val rnd: Random = SecureRandom()

    fun generateSessionId(): String {
        val bytes = ByteArray(32)
        rnd.nextBytes(bytes)
